const { DataTypes } = require('sequelize');
const sequelize = require('../config/db');

const Usuarios = sequelize.define(
  'Usuarios',
  {
    id_usuario: {
      type: DataTypes.INTEGER,
      primaryKey: true,
      autoIncrement: true,
    },
    nombre: {
      type: DataTypes.STRING(100),
      allowNull: false,
    },
    identificacion: {
      type: DataTypes.STRING(20),
      allowNull: false,
      unique: true,
    },
    telefono: {
      type: DataTypes.STRING(15),
      allowNull: true,
    },
    correo: {
      type: DataTypes.STRING(100),
      allowNull: true,
    },
    rh: {
      type: DataTypes.STRING(5),
      allowNull: true,
    },
    id_ficha: {
      type: DataTypes.INTEGER,
      allowNull: true,
      references: {
        model: 'Ficha',
        key: 'id_ficha',
      },
    },
    id_rol: {
      type: DataTypes.INTEGER,
      allowNull: false,
      references: {
        model: 'Roles',
        key: 'id_rol',
      },
    },
  },
  {
    tableName: 'Usuarios',
    timestamps: false,
    underscored: true,
  }
);

module.exports = Usuarios;
